Socket connectTo(uint16_t port) {
  const int fd = socket(AF_INET, SOCK_STREAM, 0);
  assert(fd >= 0);

  sockaddr_in address{};
  address.sin_family = AF_INET;
  address.sin_port = htons(port);
  address.sin_addr.s_addr = htonl(INADDR_LOOPBACK);

  assert(connect(fd, reinterpret_cast<sockaddr *>(&address), sizeof(address)) == 0);
  return Socket(fd);
}

std::string readAvailable(int fd) {
  std::string response;
  char buffer[4096];
  const ssize_t received = recv(fd, buffer, sizeof(buffer), 0);
  assert(received > 0);
  response.append(buffer, static_cast<size_t>(received));
  return response;
}

std::string readHttpHeaders(int fd) {
  std::string response;
  char c = '\0';
  while (response.find("\r\n\r\n") == std::string::npos) {
    assert(recv(fd, &c, 1, 0) == 1);
    response.push_back(c);
  }
  return response;
}

std::string httpRequest(uint16_t port, const std::string &request) {
  Socket socket = connectTo(port);
  assert(send(socket.fd(), request.data(), request.size(), 0) == static_cast<ssize_t>(request.size()));
  return readAvailable(socket.fd());
}

